mapper.select:
/* wms-inbound-order-returnist-sql-oracle.xml - selectInterfaceInboundReturnIstReceive - 반품입고 검수이상 처리 수신 인터페이스 조회 */
SELECT CTKEY
	 , OWKEY
	 , SOHDKEY
	 , CUSTORDNO
	 , WBLNO
	 , ICKEY
	 , PRCSYN
	 , PRCSDATE
	 , RCVDATE
	 , INSERTDATE
	 , INSERTURKEY
	 , UPDATEDATE
	 , UPDATEURKEY
  FROM TWORK_INTF_RET_ICKEYIST_RCV
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND SOHDKEY = #{orhdkey}
   AND ICKEY = #{ickey}
   AND WBLNO = #{wblno}

mapper.insert:
/* wms-inbound-order-returnist-sql-oracle.xml - deleteInterfaceInboundReturnIstReceive - 반품입고 검수이상 처리 수신 인터페이스 삭제 */
DELETE FROM TWORK_INTF_RET_ICKEYIST_RCV
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND SOHDKEY = #{sohdkey}
   AND ICKEY = #{ickey}
   AND WBLNO = #{wblno}

/* wms-inbound-order-returnist-sql-oracle.xml - insertInterfaceInboundReturnIstReceive - 반품입고 검수이상 처리 수신 인터페이스 등록 */
INSERT INTO TWORK_INTF_RET_ICKEYIST_RCV
(
	CTKEY
	, OWKEY
	, SOHDKEY
	, CUSTORDNO
	, WBLNO
	, ICKEY
	, ISTIBQTY
	, ISTRETSHIPQTY
	, ISTDSPSQTY
	, PRCSISTCONT
	, PRCSYN
	, PRCSDATE
	, RCVDATE
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
)
VALUES
(
	#{ctkey}
	, #{owkey}
	, #{orhdkey}
	, #{custordno}
	, #{wblno}
	, #{ickey}
	, #{istibqty}
	, #{istretshipqty}
	, #{istdspsqty}
	, #{prcsistcont}
	, 'N'
	, NULL
	, #{sysdate}
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
)

mapper.select:
/* wms-inbound-order-returnist-sql-oracle.xml - selectInboundDetailInfo - 반품입고 검수이상 처리 수신 인터페이스 - 입고 헤더 조회 */
SELECT CTKEY
	 , OWKEY
	 , IBHDKEY
	 , ORHDKEY
	 , ICKEY
	 , WBLNO
	 , RIPRGRSTATUSCD
  FROM TWORK_INFO_IB_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND ORHDKEY = #{orhdkey}
   AND ICKEY = #{ickey}
   AND WBLNO = #{wblno}

mapper.update:
/* wms-inbound-order-returnist-sql-oracle.xml - updateInboundOrderDetail - 반품입고 상세 검수이상 처리 UPDATE */
UPDATE TWORK_INFO_IB_DT
   SET RIPRGRSTATUSCD = #{riprgrstatuscd}
	 , ISTIBQTY   	  = #{istibqty}
	 , ISTRETSHIPQTY  = #{istretshipqty}
	 , ISTDSPSQTY     = #{istdspsqty}
	 , PRCSISTCONT    = #{prcsistcont}

	 , HOLDPRCSPCKYN  = #{holdprcspckyn}

	 , UPDATEDATE     = #{sysdate}
	 , UPDATEURKEY    = #{surkey}
 WHERE CTKEY 		  = #{ctkey}
   AND OWKEY 		  = #{owkey}
   AND IBHDKEY 		  = #{ibhdkey}
   AND ICKEY 		  = #{ickey}
   AND WBLNO  		  = #{wblno}

/* wms-inbound-order-returnist-sql-oracle.xml - updateInboundOrderWbl - 반품입고 운송장 검수이상 처리 UPDATE */
UPDATE TWORK_INFO_IBRET_WBLNO
   SET WBLPRGRSTATUSCD = #{wblprgrstatuscd}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND WBLNO = #{wblno}

/* wms-inbound-order-returnist-sql-oracle.xml - updateInterfaceInboundReturnIst - 반품입고 검수이상 처리 수신 인터페이스 처리 UPDATE */
UPDATE TWORK_INTF_RET_ICKEYIST_RCV
   SET PRCSYN = 'Y'
	 , PRCSDATE = #{sysdate}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND SOHDKEY = #{orhdkey}
   AND ICKEY = #{ickey}
   AND WBLNO = #{wblno}
